import psycopg2

def search_users(username, email, role, status):
    # Connect to the PostgreSQL database
    conn = psycopg2.connect(
        host="localhost",
        database="mydatabase",
        user="myuser",
        password="mypassword"
    )

    # Create a cursor object
    cur = conn.cursor()

    # Define the SQL query
    query = "SELECT * FROM users WHERE username LIKE %s AND email LIKE %s AND role IN (%s) AND status IN (%s)"

    # Fetch the user profiles based on the filter criteria
    cur.execute(query, (f"{username}%", f"{email}%", role, status))

    # Return the results as a list of dictionaries
    return [dict(row) for row in cur]